#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <cassert>
#include <sys/time.h>
#include <omp.h>

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

#define STR_SIZE 256
#define EXPAND_RATE 2

#define MAX_PD (3.0e6)
#define PRECISION 0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP 0.5

#define MIN(a, b) ((a) <= (b) ? (a) : (b))
#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))

static const float t_chip = 0.0005f;
static const float chip_height = 0.016f;
static const float chip_width = 0.016f;
static const float amb_temp = 80.0f;

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_init_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;

static inline void tvsub(const struct timeval *end, const struct timeval *start, struct timeval *res) {
    res->tv_sec = end->tv_sec - start->tv_sec;
    res->tv_usec = end->tv_usec - start->tv_usec;
    if (res->tv_usec < 0) {
        res->tv_sec--;
        res->tv_usec += 1000000;
    }
}
#endif

static void fatal(const char *s) {
    std::fprintf(stderr, "Error: %s\n", s);
    std::exit(1);
}

void writeoutput(float *vect, int grid_rows, int grid_cols, char *file) {
    int i, j, index = 0;
    FILE *fp;
    char str[STR_SIZE];

    if ((fp = std::fopen(file, "w")) == 0)
        std::printf("The file was not opened\n");

    for (i = 0; i < grid_rows; i++)
        for (j = 0; j < grid_cols; j++) {
            std::sprintf(str, "%d\t%g\n", index, vect[i * grid_cols + j]);
            std::fputs(str, fp);
            index++;
        }

    std::fclose(fp);
}

void readinput(float *vect, int grid_rows, int grid_cols, char *file) {
    int i, j;
    FILE *fp;
    char str[STR_SIZE];
    float val;

    if ((fp = std::fopen(file, "r")) == 0)
        fatal("The file was not opened");

    for (i = 0; i <= grid_rows - 1; i++)
        for (j = 0; j <= grid_cols - 1; j++) {
            if (std::fgets(str, STR_SIZE, fp) == NULL) fatal("Error reading file\n");
            if (std::feof(fp))
                fatal("not enough lines in file");

            if ((std::sscanf(str, "%f", &val) != 1))
                fatal("invalid file format");
            vect[i * grid_cols + j] = val;
        }

    std::fclose(fp);
}

static void hotspot_kernel_omp(
    int iteration,
    const float *power,
    const float *temp_src,
    float *temp_dst,
    int grid_cols,
    int grid_rows,
    int border_cols,
    int border_rows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step,
    int blockCols,
    int blockRows)
{
    const float step_div_Cap = step / Cap;
    const float Rx_1 = 1.0f / Rx;
    const float Ry_1 = 1.0f / Ry;
    const float Rz_1 = 1.0f / Rz;

#pragma omp parallel for collapse(2) schedule(static)
    for (int by = 0; by < blockRows; by++) {
        for (int bx = 0; bx < blockCols; bx++) {
            float temp_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
            float power_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
            float temp_t[BLOCK_SIZE][BLOCK_SIZE];

            int small_block_rows = BLOCK_SIZE - iteration * 2;
            int small_block_cols = BLOCK_SIZE - iteration * 2;

            int blkY = small_block_rows * by - border_rows;
            int blkX = small_block_cols * bx - border_cols;
            int blkYmax = blkY + BLOCK_SIZE - 1;
            int blkXmax = blkX + BLOCK_SIZE - 1;

            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int yidx = blkY + ty;
                    int xidx = blkX + tx;
                    int index = grid_cols * yidx + xidx;
                    if (IN_RANGE(yidx, 0, grid_rows - 1) && IN_RANGE(xidx, 0, grid_cols - 1)) {
                        temp_on_cuda[ty][tx] = temp_src[index];
                        power_on_cuda[ty][tx] = power[index];
                    }
                }
            }

            int validYmin = (blkY < 0) ? -blkY : 0;
            int validYmax = (blkYmax > grid_rows - 1) ? BLOCK_SIZE - 1 - (blkYmax - grid_rows + 1) : BLOCK_SIZE - 1;
            int validXmin = (blkX < 0) ? -blkX : 0;
            int validXmax = (blkXmax > grid_cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - grid_cols + 1) : BLOCK_SIZE - 1;

            for (int i = 0; i < iteration; i++) {
                for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                        int N = ty - 1;
                        int S = ty + 1;
                        int W = tx - 1;
                        int E = tx + 1;

                        N = (N < validYmin) ? validYmin : N;
                        S = (S > validYmax) ? validYmax : S;
                        W = (W < validXmin) ? validXmin : W;
                        E = (E > validXmax) ? validXmax : E;

                        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) &&
                            IN_RANGE(ty, i + 1, BLOCK_SIZE - i - 2) &&
                            IN_RANGE(tx, validXmin, validXmax) &&
                            IN_RANGE(ty, validYmin, validYmax)) {
                            temp_t[ty][tx] =
                                temp_on_cuda[ty][tx] + step_div_Cap *
                                (power_on_cuda[ty][tx] +
                                 (temp_on_cuda[S][tx] + temp_on_cuda[N][tx] - 2.0f * temp_on_cuda[ty][tx]) * Ry_1 +
                                 (temp_on_cuda[ty][E] + temp_on_cuda[ty][W] - 2.0f * temp_on_cuda[ty][tx]) * Rx_1 +
                                 (amb_temp - temp_on_cuda[ty][tx]) * Rz_1);
                        }
                    }
                }

                if (i == iteration - 1)
                    break;

                for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) &&
                            IN_RANGE(ty, i + 1, BLOCK_SIZE - i - 2) &&
                            IN_RANGE(tx, validXmin, validXmax) &&
                            IN_RANGE(ty, validYmin, validYmax)) {
                            temp_on_cuda[ty][tx] = temp_t[ty][tx];
                        }
                    }
                }
            }

            if (iteration > 0) {
                int i = iteration - 1;
                for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) &&
                            IN_RANGE(ty, i + 1, BLOCK_SIZE - i - 2) &&
                            IN_RANGE(tx, validXmin, validXmax) &&
                            IN_RANGE(ty, validYmin, validYmax)) {
                            int yidx = blkY + ty;
                            int xidx = blkX + tx;
                            int index = grid_cols * yidx + xidx;
                            temp_dst[index] = temp_t[ty][tx];
                        }
                    }
                }
            }
        }
    }
}

int compute_tran_temp(float *MatrixPower, float *MatrixTemp[2], int col, int row,
                      int total_iterations, int num_iterations, int blockCols, int blockRows,
                      int borderCols, int borderRows, float *TempCPU, float *PowerCPU)
{
    (void)TempCPU;
    (void)PowerCPU;

    float grid_height = chip_height / row;
    float grid_width = chip_width / col;

    float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    float Rx = grid_width / (2.0f * K_SI * t_chip * grid_height);
    float Ry = grid_height / (2.0f * K_SI * t_chip * grid_width);
    float Rz = t_chip / (K_SI * grid_height * grid_width);

    float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    float step = PRECISION / max_slope;
    int t;

    int src = 0, dst = 1;

    for (t = 0; t < total_iterations; t += num_iterations) {
        int iter = MIN(num_iterations, total_iterations - t);
#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif
        hotspot_kernel_omp(iter, MatrixPower, MatrixTemp[src], MatrixTemp[dst],
                           col, row, borderCols, borderRows, Cap, Rx, Ry, Rz, step,
                           blockCols, blockRows);
#ifdef TIMING
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif
        src = 1 - src;
        dst = 1 - dst;
    }

    return src;
}

void usage(int argc, char **argv) {
    std::fprintf(stderr, "Usage: %s <grid_rows/grid_cols> <pyramid_height> <sim_time> <temp_file> <power_file> <output_file> [-p platform_id] [-d device_id]\n", argv[0]);
    std::fprintf(stderr, "\t<grid_rows/grid_cols>  - number of rows/cols in the grid (positive integer)\n");
    std::fprintf(stderr, "\t<pyramid_height> - pyramid heigh(positive integer)\n");
    std::fprintf(stderr, "\t<sim_time>   - number of iterations\n");
    std::fprintf(stderr, "\t<temp_file>  - name of the file containing the initial temperature values of each cell\n");
    std::fprintf(stderr, "\t<power_file> - name of the file containing the dissipated power values of each cell\n");
    std::fprintf(stderr, "\t<output_file> - name of the output file\n");
    std::exit(1);
}

int main(int argc, char **argv) {
    std::printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);

    int size;
    int grid_rows, grid_cols = 0;
    float *FilesavingTemp, *FilesavingPower;
    char *tfile, *pfile, *ofile;

    int total_iterations = 60;
    int pyramid_height = 1;

    if (argc < 7)
        usage(argc, argv);
    if ((grid_rows = std::atoi(argv[1])) <= 0 ||
        (grid_cols = std::atoi(argv[1])) <= 0 ||
        (pyramid_height = std::atoi(argv[2])) <= 0 ||
        (total_iterations = std::atoi(argv[3])) <= 0)
        usage(argc, argv);

    tfile = argv[4];
    pfile = argv[5];
    ofile = argv[6];
    size = grid_rows * grid_cols;

    int platform_id_inuse = 0;
    int device_id_inuse = 0;

    int cur_arg;
    for (cur_arg = 1; cur_arg < argc; cur_arg++) {
        if (std::strcmp(argv[cur_arg], "-h") == 0)
            usage(argc, argv);
        else if (std::strcmp(argv[cur_arg], "-p") == 0) {
            if (argc >= cur_arg + 1) {
                platform_id_inuse = std::atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (std::strcmp(argv[cur_arg], "-d") == 0) {
            if (argc >= cur_arg + 1) {
                device_id_inuse = std::atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
    }

    (void)platform_id_inuse;
    (void)device_id_inuse;

    int borderCols = (pyramid_height) * EXPAND_RATE / 2;
    int borderRows = (pyramid_height) * EXPAND_RATE / 2;
    int smallBlockCol = BLOCK_SIZE - (pyramid_height) * EXPAND_RATE;
    int smallBlockRow = BLOCK_SIZE - (pyramid_height) * EXPAND_RATE;
    int blockCols = grid_cols / smallBlockCol + ((grid_cols % smallBlockCol == 0) ? 0 : 1);
    int blockRows = grid_rows / smallBlockRow + ((grid_rows % smallBlockRow == 0) ? 0 : 1);

    FilesavingTemp = (float *)std::malloc(size * sizeof(float));
    FilesavingPower = (float *)std::malloc(size * sizeof(float));

    if (!FilesavingPower || !FilesavingTemp)
        fatal("unable to allocate memory");

    readinput(FilesavingTemp, grid_rows, grid_cols, tfile);
    readinput(FilesavingPower, grid_rows, grid_cols, pfile);

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    std::printf("Platform: OpenMP\n");
    std::printf("num_devices = 1\n");
    std::printf("Device: CPU\n");
    std::printf("Use CPU device\n");

    float *MatrixTemp[2];
    MatrixTemp[0] = FilesavingTemp;
    MatrixTemp[1] = (float *)std::malloc(sizeof(float) * size);
    if (!MatrixTemp[1]) fatal("unable to allocate memory");

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_mem_alloc_end, &tv);
    h2d_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    int ret = compute_tran_temp(FilesavingPower, MatrixTemp, grid_cols, grid_rows, total_iterations, pyramid_height,
                                blockCols, blockRows, borderCols, borderRows, FilesavingTemp, FilesavingPower);

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif
    float *MatrixOut = MatrixTemp[ret];
#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    writeoutput(MatrixOut, grid_rows, grid_cols, ofile);

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    std::free(MatrixTemp[1]);
    std::free(FilesavingPower);
    std::free(FilesavingTemp);

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    std::printf("Init: %f\n", init_time);
    std::printf("MemAlloc: %f\n", mem_alloc_time);
    std::printf("HtoD: %f\n", h2d_time);
    std::printf("Exec: %f\n", kernel_time);
    std::printf("DtoH: %f\n", d2h_time);
    std::printf("Close: %f\n", close_time);
    std::printf("Total: %f\n", total_time);
#endif

    return 0;
}
